final:
module RefModule(  
    input clk,  
    input load,  
    input [1:0] data_in,  
    output reg [1:0] q  
);  
      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin  
        if (load)  
            q <= data_in;  
        else  
            q <= {q[0], 1'b0};  
    end  
endmodule
